# ── Helper functions ────────────────────────────────────────────────────────────
@st.cache_data
def load_system_prompt():
    try:
        with open("system_prompt.txt", "r", encoding="utf-8") as f:
            return f.read()
    except FileNotFoundError:
        return "You are Lyra, a helpful beauty consultant for Forever 21 Beauty Studio."

def load_logo():
    try:
        with open("f21_logo_new.png", "rb") as f:
            return base64.b64encode(f.read()).decode()
    except FileNotFoundError:
        return None

@st.cache_resource
def get_gemini_client():
    return genai.Client(api_key=st.secrets["GOOGLE_API_KEY"])

def get_sheet():
    sa_info = dict(st.secrets["gcp_service_account"])
    creds = Credentials.from_service_account_info(
        sa_info, scopes=["https://www.googleapis.com/auth/spreadsheets"]
    )
    gc = gspread.authorize(creds)
    return gc.open_by_key(st.secrets["GOOGLE_SHEET_ID"]).worksheet("Leads")

def save_lead_to_sheet(name, phone, source="Website"):
    try:
        sheet = get_sheet()
        # ist_timezone — convert UTC to IST (UTC+5:30)
        _ist = datetime.utcnow() + timedelta(hours=5, minutes=30)
        sheet.append_row([_ist.strftime("%d-%m-%Y %H:%M"),
                          name, phone, "New Lead", source])
        return True
    except Exception as e:
        st.error(f"Sheet error: {e}")
        return False

def chat_with_lyra(messages, system_prompt):
    client = get_gemini_client()
    gemini_messages = [
        types.Content(
            role="user" if m["role"] == "user" else "model",
            parts=[types.Part(text=m["content"])]
        ) for m in messages
    ]
    response = client.models.generate_content(
        model="gemini-2.5-flash",
        config=types.GenerateContentConfig(system_instruction=system_prompt),
        contents=gemini_messages,
    )
    return response.text

def extract_lead(text):
    pattern = r'LEAD_CAPTURED:\{"name":"([^"]+)","phone":"([^"]+)"\}'
    match = re.search(pattern, text)
    if match:
        return re.sub(pattern, "", text).strip(), match.group(1), match.group(2)
    return text, None, None

def format_duration(minutes):
    if minutes < 60:
        return f"{minutes} min"
    h = minutes // 60
    m = minutes % 60
    if m == 0:
        return f"{h}h"
    return f"{h}h {m}min"

def parse_date(ts):
    try:
        return datetime.strptime(ts[:10], "%d-%m-%Y").date()
    except Exception:
        return date(2026, 1, 1)

